{"file_path":"/project/kotlinx-coroutines-core/common/test/flow/operators/TimeoutFailedChannelTest.kt","content":"package kotlinx.coroutines.flow.operators

import kotlinx.coroutines.testing.*
import kotlinx.coroutines.flow.*
import kotlin.test.*
import kotlin.time.Duration.Companion.seconds

class TimeoutFailedChannelTest : TestBase() {

    @Test
    fun testCallbackFlowCloseWithExceptionPropagates() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val e = assertFailsWith<IllegalStateException> { flow.collect() }
        assertEquals("Test Exception", e.message)
    }
}
"}

